// Constants
const AUTH_URL = 'YOUR_AUTH_URL';
const TOKEN_URL = 'YOUR_TOKEN_URL';

// Helper function to set tokens in localStorage
const setTokens = (tokens) => {
  localStorage.setItem('accessToken', tokens.access_token);
  localStorage.setItem('refreshToken', tokens.refresh_token);
};

// Function to handle authorization code exchange
const exchangeCode = (code) => {
  const data = {
    grant_type: 'authorization_code',
    code: code,
    client_id: 'YOUR_CLIENT_ID',
    client_secret: 'YOUR_CLIENT_SECRET',
    redirect_uri: 'YOUR_REDIRECT_URI',
  };

  fetch(TOKEN_URL, {
    method: 'POST',
    headers: {
      'Content-Type': 'application/x-www-form-urlencoded',
    },
    body: new URLSearchParams(data),
  })
    .then((response) => response.json())
    .then((tokens) => {
      setTokens(tokens);
      // Redirect to home page or perform other actions
    })
    .catch((error) => {
      console.error('Error exchanging code:', error);
    });
};

// Function to get authorization code
const getAuthorizationCode = () => {
  const urlParams = new URLSearchParams(window.location.search);
  const code = urlParams.get('code');

  if (code) {
    exchangeCode(code);
  } else {
    // Handle case where authorization code is not present
  }
};

// Event listener for start of turn
window.addEventListener('start_of_turn', getAuthorizationCode);